"""HLD Key Technologies: Redis, Elasticsearch, Kafka — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def redis_lesson() -> Lesson:
    return Lesson(id="hld-redis", number=116, title="Redis",
        focus=("data structures","persistence","clustering","pub/sub","Lua scripts","eviction"),
        overview="Redis is the Swiss-army knife of system design. Know its data structures, persistence, and clustering internals.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("redis-1","What is Redis' threading model?","hard",("redis",),("A transport layer optimization that reduces round-trip overhead using multiplexing","A partitioning algorithm that assigns data based on a hash of the geographic region","A consensus protocol that uses a rotating leader to distribute write coordination load","Single-threaded event loop for commands; avoids locking overhead. I/O threads added in 6.0"),3,"Single-threaded means no locks, no context switches. In-memory ops are so fast one thread saturates network."),
        quiz("redis-2","What are the main Redis data structures?","medium",("redis",),("Strings, Hashes, Lists, Sets, Sorted Sets, Streams, HyperLogLog, Bitmaps","A query optimization strategy that rewrites subqueries into more efficient join patterns","A consistency model where reads from any replica are guaranteed to be monotonically fresh","A transaction isolation level that prevents phantom reads using predicate locking"),0,"Each structure has specialized commands and use cases. Sorted Sets for leaderboards, Streams for event logs."),
        quiz("redis-3","What is a Redis Sorted Set and when would you use it?","hard",("redis",),("A set where each member has a score, supporting O(log n) ranked queries — ideal for leaderboards","An index maintenance operation that rebuilds fragmented pages for better scan performance","A data structure that stores cache metadata compactly using probabilistic counting","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool"),0,"ZADD/ZRANGE/ZRANK: perfect for leaderboards, priority queues, time-windowed aggregations."),
        quiz("redis-4","What is the difference between RDB and AOF persistence?","hard",("redis",),("A persistence mechanism that snapshots the cache state to disk for crash recovery","A state synchronization approach that reconciles differences using Merkle tree comparison","A process that periodically reconciles state between systems to detect and fix drift","RDB: periodic point-in-time snapshots. AOF: append-every-write log. RDB is compact; AOF is more durable"),3,"Best practice: use both. AOF for durability (fsync every second). RDB for fast restarts."),
        quiz("redis-5","How does Redis Cluster shard data?","hard",("redis",),("16384 hash slots distributed across master nodes; each key maps to CRC16(key) mod 16384","A schema design pattern that embeds frequently accessed data to avoid join overhead","A clock synchronization technique that uses NTP with bounded drift for ordering events","A communication pattern where services exchange messages through a centralized broker"),0,"Clients compute the slot and connect directly to the owning node. MOVED/ASK redirects handle migrations."),
        quiz("redis-6","What is Redis pub/sub and its limitation?","medium",("redis",),("A deployment strategy that gradually shifts traffic from the old version to the new one","A technique that partitions workload across worker pools based on resource requirements","Fire-and-forget messaging; messages are lost if no subscriber is listening at the time","A flow control mechanism that prevents the sender from overwhelming the receiver"),2,"Pub/sub doesn't persist. For durability, use Redis Streams (XADD/XREAD with consumer groups)."),
        quiz("redis-7","What is Redis Streams vs pub/sub?","hard",("redis",),("A load shedding strategy that drops low-priority requests when resource utilization is high","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A routing strategy that directs traffic based on geographic proximity of the client","Streams persist messages, support consumer groups with acknowledgment; pub/sub is fire-and-forget"),3,"Streams (XADD/XREAD/XACK) provide Kafka-like semantics within Redis."),
        quiz("redis-8","What is the Redis eviction policy LRU vs LFU?","hard",("redis",),("A data pipeline stage that transforms and enriches events before writing to storage","A congestion avoidance algorithm that dynamically adjusts the transmission window","volatile-lru: evict least recently used keys with TTL. allkeys-lfu: evict least frequently used from all keys","A replication technique that synchronously mirrors writes to a standby for zero data loss"),2,"Choose based on access pattern. LFU is better for skewed workloads where some keys are always hot."),
        quiz("redis-9","What is Redis Sentinel?","hard",("redis",),("Provides high availability with automatic failover: monitors masters, detects failure, promotes replicas","A protocol that batches multiple requests into a single TCP segment for efficiency","A connection management approach that pins clients to specific backend instances","An eviction algorithm that considers both recency and frequency when selecting victims"),0,"Sentinel: quorum-based failure detection → automatic promotion → client notification of new master."),
        quiz("redis-10","What is the Redis MULTI/EXEC transaction?","hard",("redis",),("A resilience pattern that isolates failures in one subsystem from propagating to others","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","A cache coherence protocol that broadcasts invalidation messages to all cache tiers","Queues commands and executes atomically — but no rollback on individual command failure"),3,"MULTI/EXEC: all-or-nothing execution. WATCH enables optimistic locking (CAS pattern)."),
        quiz("redis-11","What is Redis Lua scripting?","hard",("redis",),("A pattern where incoming requests are buffered and processed in priority-ordered batches","A backup mechanism that captures incremental changes since the last full snapshot","Execute Lua scripts atomically on the server — enables complex operations without round trips","A technique where the server pre-fetches resources based on predicted client needs"),2,"EVAL: server-side atomic execution. Useful for rate limiting, token bucket, and complex CAS operations."),
        quiz("redis-12","What is the Redis HyperLogLog?","hard",("redis",),("A probabilistic data structure for cardinality estimation (count unique items) with O(1) space","A sharding approach that distributes cached entries across nodes by consistent hashing","A monitoring tool that tracks query execution plans and identifies slow running queries","A connection management approach that limits concurrent sessions to prevent overload"),0,"PFADD/PFCOUNT: count unique visitors with only 12KB memory, ~0.81% standard error."),
        quiz("redis-13","How does Redis replication work?","hard",("redis",),("A warming strategy that pre-loads data based on access frequency from the previous day","A serialization format that reduces cache entry size through schema-aware compression","A prefetching algorithm that predicts future access patterns from recent query history","Async replication from master to replicas. Initial full sync (RDB dump) then incremental command stream"),3,"Async replication means replicas may lag. For strong consistency, use WAIT command."),
        quiz("redis-14","What is Redis pipelining?","medium",("redis",),("A load balancing technique using configurable thresholds","A storage engine optimization that pre-sorts data on disk for sequential access patterns","A DNS-based technique that distributes queries across multiple authoritative servers","Sending multiple commands without waiting for replies, then reading all replies — reduces round-trip overhead"),3,"Pipelining: send 1000 commands → get 1000 replies in one round trip. 10x throughput improvement."),
        quiz("redis-15","What is the Redis Bitmap data structure?","hard",("redis",),("A compact bit array supporting SETBIT/GETBIT/BITCOUNT — perfect for tracking binary states per user","A coordination service that uses ephemeral nodes for automatic failure detection","A replication strategy where writes go to any node and conflicts are resolved on read","A replication technique that mirrors hot cache entries across multiple nodes for availability"),0,"Bitmap: track 1B users' daily login with only 125MB. BITCOUNT for analytics. BITOP for set operations."),
        quiz("redis-16","What are the risks of using Redis as a primary database?","hard",("redis",),("Data loss if persistence isn't configured properly; limited by RAM size; no complex queries/JOINs","A partitioning strategy that splits data based on a hash of the composite primary key","A testing approach that injects controlled failures to verify system recovery behavior","A membership protocol where nodes periodically exchange state with random cluster peers"),0,"Redis works as a primary DB for specific use cases (sessions, caches) but not for general transactional data."),
        quiz("redis-17","What is Redis Cluster's split-brain handling?","hard",("redis",),("A scheduling algorithm that assigns tasks to workers based on estimated completion time","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests","Minority partition nodes stop accepting writes after a timeout; clients reconnect to majority partition","A security protocol that authenticates both client and server during the handshake"),2,"cluster-node-timeout: nodes in minority partition become read-only. Prevents conflicting writes."),
        quiz("redis-18","How do you implement a distributed lock with Redis?","hard",("redis",),("SETNX + DELETE — commonly used in production environments","SET key value NX PX milliseconds (atomic acquire with TTL); DEL to release. Redlock for multi-node","MULTI/EXEC only — commonly used in production environments","INCR/DECR — commonly used in production environments"),1,"SET NX PX: atomic acquire. TTL prevents deadlocks. Check lock value before releasing to prevent stale releases."),
        quiz("redis-19","What is Redis Cluster resharding?","hard",("redis",),("Add new cluster — commonly used in production environments","Moving hash slots between nodes online — MIGRATE command moves keys slot by slot while serving traffic","Deleting data — commonly used in production environments","Restart cluster — commonly used in production environments"),1,"redis-cli --cluster reshard: moves slots live. ASK redirects handle in-flight migrations."),
        quiz("redis-20","What is the memory overhead per key in Redis?","hard",("redis",),("0 bytes — commonly used in production environments","1 KB — commonly used in production environments","~50-70 bytes per key for internal structures (dict entry, SDS string, expiry) regardless of value size","1 byte — commonly used in production environments"),2,"With 1B small keys, overhead alone = ~50-70GB. Use hash packing for small values to reduce overhead."),
    ))

def elasticsearch_lesson() -> Lesson:
    return Lesson(id="hld-elasticsearch", number=117, title="Elasticsearch",
        focus=("inverted index","sharding","relevance scoring","aggregations","ELK stack","mapping"),
        overview="Elasticsearch powers search, analytics, and logging. Know its internals and query capabilities.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("es-1","What is Elasticsearch optimized for?","medium",("elasticsearch",),("Graph traversal — commonly used in production environments","Time-series only — commonly used in production environments","ACID transactions — commonly used in production environments","Full-text search, analytics, and log aggregation using inverted indexes"),3,"ES uses inverted indexes for fast text search. Great for log analytics (ELK) and fuzzy matching."),
        quiz("es-2","What is an inverted index?","hard",("elasticsearch",),("A hash table — commonly used in production environments","A B-tree — commonly used in production environments","A data structure mapping each unique term to the list of documents containing it","A sorted array — commonly used in production environments"),2,"Inverted index: term → [doc1, doc5, doc42]. O(1) lookup of which documents contain a search term."),
        quiz("es-3","How does Elasticsearch shard data?","hard",("elasticsearch",),("By time only — commonly used in production environments","Single node only — commonly used in production environments","No sharding — commonly used in production environments","Each index is split into primary shards distributed across nodes; each shard is a self-contained Lucene index"),3,"Default: 1 primary shard per index. Shards enable horizontal scaling. Replica shards add fault tolerance."),
        quiz("es-4","What is the difference between a primary and replica shard?","medium",("elasticsearch",),("Primary handles writes; replicas serve reads and provide failover if primary fails","Replica handles writes — commonly used in production environments","Same thing — commonly used in production environments","Primary is a backup — commonly used in production environments"),0,"Replicas: read scaling + fault tolerance. A replica can be promoted to primary on node failure."),
        quiz("es-5","What is TF-IDF in Elasticsearch?","hard",("elasticsearch",),("A database index — commonly used in production environments","Term Frequency × Inverse Document Frequency — a relevance scoring formula for full-text search","A sharding strategy — commonly used in production environments","A caching algorithm — commonly used in production environments"),1,"TF-IDF: rare terms matching a document score higher. ES now uses BM25 (improved TF-IDF) by default."),
        quiz("es-6","What is BM25?","hard",("elasticsearch",),("A database version — commonly used in production environments","A caching policy — commonly used in production environments","A shard strategy — commonly used in production environments","Okapi BM25: the default relevance scoring algorithm in ES — improves on TF-IDF with term frequency saturation"),3,"BM25 prevents very high term frequencies from dominating scores. Better than raw TF-IDF."),
        quiz("es-7","What is the ELK stack?","medium",("elasticsearch",),("Elasticsearch (search/analytics) + Logstash (ingestion) + Kibana (visualization)","A caching layer — commonly used in production environments","A database cluster — commonly used in production environments","A CDN — commonly used in production environments"),0,"ELK: the go-to for log aggregation, monitoring, and observability."),
        quiz("es-8","What is a mapping in Elasticsearch?","medium",("elasticsearch",),("A configuration file — commonly used in production environments","A routing table — commonly used in production environments","Schema definition: specifies field types (text, keyword, integer, date) and how they're indexed","A geographic feature — commonly used in production environments"),2,"Mapping controls tokenization (text vs keyword), indexing options, and stored fields."),
        quiz("es-9","What is the difference between text and keyword field types?","hard",("elasticsearch",),("Text is analyzed (tokenized, lowercased) for full-text search; keyword is exact match (no tokenization)","Text is faster — commonly used in production environments","Keyword supports fuzzy — commonly used in production environments","Same thing — commonly used in production environments"),0,"Use text for searchable content. Use keyword for exact matches, sorting, and aggregations."),
        quiz("es-10","What is an analyzer in Elasticsearch?","hard",("elasticsearch",),("A shard strategy — commonly used in production environments","A data type — commonly used in production environments","A monitoring tool — commonly used in production environments","A pipeline of character filters, tokenizer, and token filters that processes text for indexing/search"),3,"Standard analyzer: lowercase + tokenize. Custom analyzers handle stemming, synonyms, stopwords."),
        quiz("es-11","How does Elasticsearch handle near-real-time search?","hard",("elasticsearch",),("Real-time always — commonly used in production environments","After commit only — commonly used in production environments","Documents are searchable after a refresh interval (~1 second) when in-memory buffer is written to a segment","Instant indexing — commonly used in production environments"),2,"Refresh creates a new searchable segment from the in-memory buffer. Default interval: 1 second."),
        quiz("es-12","What is a segment in Elasticsearch?","hard",("elasticsearch",),("A database table — commonly used in production environments","A shard subset — commonly used in production environments","A replica — commonly used in production environments","An immutable Lucene index file; new documents create new segments, which are periodically merged"),3,"Segments are immutable. Deletes create tombstones. Merging compacts segments and removes tombstones."),
        quiz("es-13","What are aggregations in Elasticsearch?","medium",("elasticsearch",),("A caching feature — commonly used in production environments","A replication mode — commonly used in production environments","SQL JOINs — commonly used in production environments","Analytics operations: bucket (group by), metric (avg, sum), and pipeline aggregations on search results"),3,"Aggregations enable dashboard analytics: top terms, date histograms, percentiles, nested buckets."),
        quiz("es-14","What is the document routing in Elasticsearch?","hard",("elasticsearch",),("Load balancing — commonly used in production environments","DNS routing — commonly used in production environments","By default, shard = hash(document_id) % num_primary_shards. Custom routing co-locates related docs","A CDN feature — commonly used in production environments"),2,"Custom routing: all docs for a tenant go to the same shard, enabling efficient single-shard queries."),
        quiz("es-15","What is the difference between Elasticsearch and a relational database?","medium",("elasticsearch",),("ES: denormalized, search-optimized, eventually consistent. RDBMS: normalized, transactional, strongly consistent","ES is a database replacement across multiple service instances","No difference — commonly used in production environments","RDBMS supports full-text search for improved throughput"),0,"ES is NOT a primary database. It's a search engine used as a read-optimized projection."),
        quiz("es-16","What is the scroll API in Elasticsearch?","hard",("elasticsearch",),("Pagination — commonly used in production environments","Efficiently retrieves large result sets by keeping a point-in-time snapshot, avoiding deep pagination costs","A caching feature — commonly used in production environments","A write API — commonly used in production environments"),1,"Scroll: for batch processing. Search_after: for live pagination. Both avoid the deep-pagination O(n) problem."),
        quiz("es-17","How does Elasticsearch handle updates?","hard",("elasticsearch",),("Direct modification — commonly used in production environments","In-place updates — commonly used in production environments","Documents are immutable; an update creates a new version and marks the old one as deleted","SQL UPDATE — commonly used in production environments"),2,"Lucene segments are immutable. Updates = delete old + index new. Merging reclaims deleted space."),
        quiz("es-18","What is cross-cluster replication in Elasticsearch?","hard",("elasticsearch",),("Within one cluster — commonly used in production environments","Replicating indices across geographically separate clusters for disaster recovery and local reads","A node type — commonly used in production environments","A shard feature — commonly used in production environments"),1,"CCR: leader cluster → follower cluster. Follower serves local reads. Failover if leader goes down."),
        quiz("es-19","What is the percolate query?","hard",("elasticsearch",),("An aggregation — commonly used in production environments","Reverse search: store queries, then match new documents against stored queries (alerting, notifications)","A filter — commonly used in production environments","A standard search — commonly used in production environments"),1,"Percolate: 'which of my saved searches match this new document?' Used for alerts and saved searches."),
        quiz("es-20","How do you handle Elasticsearch at scale?","hard",("elasticsearch",),("Shard per tenant/time, hot-warm-cold architecture, index lifecycle management, and force-merge old indices","Single large node — commonly used in production environments","No scaling needed — commonly used in production environments","Just add RAM — commonly used in production environments"),0,"ILM: hot (SSD, recent) → warm (HDD, older) → cold (frozen, archive). Auto-manages index lifecycle."),
    ))

def kafka_lesson() -> Lesson:
    return Lesson(id="hld-kafka", number=118, title="Kafka",
        focus=("partitions","consumer groups","offsets","replication","exactly-once","Kafka Streams"),
        overview="Kafka is the backbone of event-driven architecture. Know partitions, consumer groups, and delivery guarantees.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("kafka-1","What makes Kafka different from a traditional queue?","hard",("kafka",),("Kafka is simpler — commonly used in production environments","Kafka is faster — commonly used in production environments","Kafka doesn't order — commonly used in production environments","Kafka is a distributed commit log: retains messages, allows replay, and supports multiple consumer groups"),3,"Unlike RabbitMQ, Kafka retains messages after consumption. Consumers track their offset."),
        quiz("kafka-2","What is a Kafka partition?","hard",("kafka",),("A consumer group — commonly used in production environments","A database shard — commonly used in production environments","A topic — commonly used in production environments","The unit of parallelism — messages are ordered within a partition, distributed across brokers"),3,"Partitions enable horizontal scaling. Ordering guaranteed only within a partition."),
        quiz("kafka-3","What is a consumer group?","medium",("kafka",),("A set of consumers sharing partition ownership — each partition consumed by exactly one member","A group of topics — commonly used in production environments","A broker cluster — commonly used in production environments","A replication mechanism — commonly used in production environments"),0,"10 partitions → max 10 consumers in a group. Adding more consumers than partitions wastes them."),
        quiz("kafka-4","What happens when a consumer falls behind?","hard",("kafka",),("Consumer lag increases; it catches up by reading from disk (retention period protects messages)","Topic paused — commonly used in production environments","Messages deleted — commonly used in production environments","Kafka stops producers — commonly used in production environments"),0,"Monitor consumer lag. If consumer can't keep up, add more consumers (up to partition count)."),
        quiz("kafka-5","What is Kafka's replication model?","hard",("kafka",),("Peer-to-peer — commonly used in production environments","Each partition has a leader and N-1 follower replicas. Writes go to leader; followers replicate asynchronously","No replication — commonly used in production environments","Multi-leader — commonly used in production environments"),1,"ISR (In-Sync Replicas): only replicas that are caught up. Leader election from ISR on failure."),
        quiz("kafka-6","What is the ISR (In-Sync Replica) set?","hard",("kafka",),("The subset of replicas that are fully caught up with the leader — only ISR members can be elected leader","A monitoring metric — commonly used in production environments","All replicas — commonly used in production environments","A consumer group — commonly used in production environments"),0,"min.insync.replicas: minimum ISR size required for acks=all. Prevents data loss on leader failure."),
        quiz("kafka-7","What is acks=all in Kafka?","hard",("kafka",),("Acknowledge to leader only with automatic failover support","Acknowledge to one broker in distributed environments","Producer waits for all ISR replicas to acknowledge the write before considering it successful","No acknowledgment — commonly used in production environments"),2,"acks=all: highest durability. acks=1: leader only (risk of loss). acks=0: fire-and-forget (fastest)."),
        quiz("kafka-8","How does Kafka achieve high throughput?","hard",("kafka",),("Single partition — commonly used in production environments","Random writes — commonly used in production environments","In-memory only — commonly used in production environments","Sequential I/O (append-only), batching, compression, zero-copy transfer, and OS page cache"),3,"Kafka writes sequentially to disk (faster than random SSD). Zero-copy: sendfile() syscall."),
        quiz("kafka-9","What is Kafka Connect?","medium",("kafka",),("A client library — commonly used in production environments","A monitoring tool — commonly used in production environments","Framework for streaming data between Kafka and external systems via source/sink connectors","A security module — commonly used in production environments"),2,"Source connectors ingest (DB→Kafka). Sink connectors export (Kafka→ES/S3). No custom code needed."),
        quiz("kafka-10","What is Kafka Streams?","hard",("kafka",),("A monitoring tool — commonly used in production environments","A message format — commonly used in production environments","A broker feature — commonly used in production environments","A client library for building stream processing applications that transform Kafka topics"),3,"Kafka Streams: stateful processing, windowing, joins — runs as a regular Java app, no separate cluster."),
        quiz("kafka-11","What is exactly-once semantics (EOS) in Kafka?","hard",("kafka",),("Only for consumers — commonly used in production environments","Impossible — commonly used in production environments","Same as at-least-once — commonly used in production environments","Idempotent producer + transactional writes + consumer read-committed = end-to-end exactly-once within Kafka"),3,"EOS: producer deduplication (idempotent) + atomic multi-partition writes (transactions) + consumer isolation."),
        quiz("kafka-12","What is a Kafka topic compaction?","hard",("kafka",),("A partition strategy — commonly used in production environments","Compression — commonly used in production environments","Log compaction retains only the latest value for each key, discarding older versions — like a changelog","Deleting old messages — commonly used in production environments"),2,"Compacted topics: keep latest state per key. Used for CDC, configuration, and state snapshots."),
        quiz("kafka-13","How does Kafka handle ordering across partitions?","hard",("kafka",),("Global ordering — commonly used in production environments","It doesn't — ordering is only within a partition. Use a single partition for strict global order (limits throughput)","Timestamp sorting — commonly used in production environments","Automatic reordering — commonly used in production environments"),1,"Design your partition key so related messages go to the same partition for ordering."),
        quiz("kafka-14","What is consumer rebalancing?","hard",("kafka",),("When consumers join/leave a group, partitions are reassigned. Causes a brief processing pause","A topic reset — commonly used in production environments","A broker restart — commonly used in production environments","Data migration — commonly used in production environments"),0,"Rebalancing can cause duplicates (at-least-once). Cooperative rebalancing (incremental) reduces impact."),
        quiz("kafka-15","What is the Schema Registry?","hard",("kafka",),("A monitoring tool — commonly used in production environments","A broker feature — commonly used in production environments","A service storing Avro/Protobuf/JSON schemas for Kafka messages, enabling schema evolution and validation","A database — commonly used in production environments"),2,"Schema Registry ensures producers and consumers agree on message format. Supports backward/forward compatibility."),
        quiz("kafka-16","What is a dead letter topic?","medium",("kafka",),("A deleted topic — commonly used in production environments","A backup topic — commonly used in production environments","An error log — commonly used in production environments","A topic where messages that fail processing are sent for later investigation and reprocessing"),3,"DLT: poison messages go here after max retries. Prevents blocking the main consumer."),
        quiz("kafka-17","What is the difference between Kafka's retention by time vs size?","medium",("kafka",),("Time is always used — commonly used in production environments","Same thing — commonly used in production environments","Size is always used — commonly used in production environments","Time-based: delete messages older than N days. Size-based: delete oldest when topic exceeds N GB"),3,"Configure per topic. Time-based for event streams. Size-based for resource-constrained environments."),
        quiz("kafka-18","What is MirrorMaker 2?","hard",("kafka",),("A schema tool — commonly used in production environments","A monitoring tool — commonly used in production environments","Kafka's built-in cross-cluster replication tool for disaster recovery and multi-datacenter setups","A consumer library — commonly used in production environments"),2,"MM2: replicate topics between clusters. Supports active-active and active-passive topologies."),
        quiz("kafka-19","How do you choose the number of partitions for a topic?","hard",("kafka",),("Based on target throughput: partitions ≥ max(producer throughput / partition throughput, consumer count)","Always 100 — commonly used in production environments","Always 1 — commonly used in production environments","Based on message size — commonly used in production environments"),0,"More partitions = more parallelism but also more overhead (file handles, memory, rebalancing time)."),
        quiz("kafka-20","What is the Kafka transaction protocol?","hard",("kafka",),("Atomic writes across multiple partitions: all messages in a transaction are committed or aborted together","Same as SQL transactions — commonly used in production environments","A locking mechanism — commonly used in production environments","A replication feature — commonly used in production environments"),0,"Transactions enable exactly-once: produce to multiple topics/partitions atomically. Used with Kafka Streams."),
    ))
